package ir.tahamohamadi.resume; import ir.tahamohamadi.common.domain.*; import ir.tahamohamadi.common.persistence.AuditedSoftDeletableEntity; import ir.tahamohamadi.media.asset.MediaAsset; import jakarta.persistence.*; import lombok.*; import java.time.Instant;
@Entity @Table(name="resume_document") @Getter @NoArgsConstructor(access=AccessLevel.PROTECTED) public class ResumeDocument extends AuditedSoftDeletableEntity { @Enumerated(EnumType.STRING) @Column(name="language_code",nullable=false,length=2) private LanguageCode languageCode; @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="media_asset_id",nullable=false) private MediaAsset mediaAsset; @Enumerated(EnumType.STRING) @Column(nullable=false) private ContentStatus status; @Column(name="published_at") private Instant publishedAt; }
